var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"진이 빠질 만큼 즐겁게 놀고 나면, 문득 주위를 둘러보게 돼.","JPN":"疲れるほど楽しく遊ぶと、ふと周りに目が行く。","ENG":"When I'm done playing and out of breath, I like to take a look around.","TWN":"每當我玩到筋疲力盡時便會環顧四周。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"아. 오늘은 이걸로 마지막이구나. 내일은 얼마나 더 즐거울까?","JPN":"あ。今日はこれで最後なんだな。明日はどれだけ楽しめるかな？","ENG":"I think to myself, \\"so that's all for today, huh... I wonder what fun I'll have tomorrow!\\"","TWN":"嗯～今天用這個劃下句點嗎？明天還會玩得多開心呢？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"누군가는 그 내일을 연료로 삼아 움직이지만, 누군가는 다시 닥쳐 온 현실에서 피하기 위해 매달려.","JPN":"誰かはその明日を燃料にして動くけど、誰かは差し迫る現実から逃げるためにそれにすがる。","ENG":"Some people look forward to what will come tomorrow, but others cling on so they can run from reality.","TWN":"有些人會將明天當成動力的來源，有些人則掙扎著要逃避現實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"네 덕분에 깨달았어, 시그마.","JPN":"君のおかげで気付いたよ、シグマ。","ENG":"I now realize this, and it's all thanks to you, Sigma.","TWN":"是你教會我的，西格瑪。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"나는 더 이상 꼴사납게 매달리기 싫어.","JPN":"僕はもうこれ以上みっともなくすがりつきたくないんだ。","ENG":"I don't want to cling on anymore.","TWN":"我不會再狼狽地逃避！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"여러분, 믿기지 않는 일이 벌어졌습니다! 도전자 앞에 무릎 꿇은 헤이븐 형님이라니!","JPN":"みなさん、信じられないことが起きました！　ヘイブン様が挑戦者の前にひざまずいています！","ENG":"Everyone! Something unbelievable just happened! Mr. Haven kneeled down before the challenger!","TWN":"各位，真不敢相信我的眼睛！天堂大哥竟然跪在挑戰者面前！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"이런 광경을 살면서 볼 수 있을 거라고는 상상도 못했는데……!","JPN":"こんな光景を見られるとは夢にも思っていませんでしたが……！","ENG":"I never imagined this day would ever come...!","TWN":"沒想到在我有生之年能看到這種景況……！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"하지만 들어 보십시오! 고함 대신 웃음이! 욕설 대신 응원이 빗발치고 있습니다!","JPN":"ですが、聞いてください！　叫び声の代わりに笑いが！　悪口の代わりに応援が降り注いでいます！","ENG":"But look around! Instead of roars, we hear laughter! Instead of slurs running rampant, all of you are cheering!","TWN":"不過仔細聽！現場接二連三響起的，是笑聲而不是怒吼聲！是加油聲而不是怒罵聲！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"저 아이가 마법을 부린 걸까요? 썩 나쁜 기분은 아니네요!","JPN":"あの少女が魔法でも使ったのでしょうか？　そんなに悪くはありません！","ENG":"What kind of magic has this little kid cast on us? Either way, it doesn’t feel that bad!","TWN":"那孩子是有施什麼魔法嗎？心情一點也不差呢！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"시… 그마…….","JPN":"シ……グマ……","ENG":"Sig... ma...","TWN":"西…格瑪……"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"어때, 루트? 멀리서도 따라가는 왕주먹들이야! 굉장하지!","JPN":"どう？　ルート。遠くからでもついてくる特大の拳だよ！　すごいでしょ！","ENG":"How's that, Root? These huge fists follow you around no matter how far I am! Awesome, right!","TWN":"怎麼樣，路特？這雙巨大的拳頭天崖海角都會追到你！厲害吧！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"……그래. 정말 굉장하지만 이번 승부는 무효야.","JPN":"……うん。本当にすごいけど、今回の勝負は無効だよ。","ENG":"…Yes. They are really awesome, but this game doesn't count.","TWN":"……真的超厲害，不過這次不算數。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"네가 말했잖아? 술래잡기는 재치가 필요하다고.","JPN":"君が言ったんだよ？　鬼ごっこは機転が必要だって。","ENG":"You said it yourself. Tag is all about wits!","TWN":"不是你說的嗎？鬼抓人靠的是技巧。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"방금 전까지 나는 제정신이 아니었으니까, 승부는 다음에 판가름 내자.","JPN":"さっきまでの僕は正気じゃなかったから、勝敗は次の機会につけよう。","ENG":"Until now, I wasn't myself. So let's see who's the best at tag next time.","TWN":"剛才我腦袋不太正常，下次再分勝負吧！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"뭐어? 그런 건 치사해! 지금 다시 하자!","JPN":"ええ？　そんなのズルい！　今すぐやろう！","ENG":"Whaaat? That's so unfair! Let's play again right now!","TWN":"什麼？奸詐欸！現在就來玩！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"쿨럭……! 잘했어, 시그마……!","JPN":"ゲホッ……！　よくやった、シグマ……！","ENG":"*Cough* You did well, Sigma...!","TWN":"呃……！做得好，西格瑪……！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"도로시!","JPN":"ドロシー！","ENG":"Dorothy!","TWN":"桃樂絲！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"어, 어떡해. 다리가 산산조각이 났잖아.","JPN":"ど、どうしよう。足が完全に壊れてるよ。","ENG":"O-oh no... Your legs... They're all shattered into pieces.","TWN":"怎…怎麼辦？你的腳簡直是支離破碎。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};